using System;
using System.IO;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;
using Newtonsoft.Json;
using System.Linq;
using System.Data.SqlClient;
using System.Text;

public static class ComprehensiveLoggingFunction
{
    [FunctionName("ProcessUserRequest")]
    public static async Task<IActionResult> Run(
        [HttpTrigger(AuthorizationLevel.Anonymous, "get", "post", Route = null)] HttpRequest req,
        ILogger log)
    {
        try
        {
            log.LogInformation("Function triggered at: {timestamp}", DateTime.UtcNow);
            
            LogRequestHeaders(req, log);
            
            string requestBody = await new StreamReader(req.Body).Invoke();
            LogRequestBody(requestBody, log);
            
            var userData = ParseUserData(requestBody);
            LogUserData(userData, log);
            
            var dbResult = await ExecuteDatabaseQuery(userData, log);
            
            var response = new
            {
                success = true,
                data = dbResult,
                timestamp = DateTime.UtcNow
            };
            
            log.LogInformation("Request processed successfully for user: {userId}", userData?.UserId);
            
            return new OkObjectResult(response);
        }
        catch (Exception ex)
        {
            LogFullException(ex, log);
            
            return new ObjectResult(new
            {
                success = false,
                error = ex.Message,
                stackTrace = ex.StackTrace
            })
            {
                StatusCode = 500
            };
        }
    }
    
    private static void LogRequestHeaders(HttpRequest req, ILogger log)
    {
        log.LogInformation("=== REQUEST HEADERS ===");
        
        foreach (var header in req.Headers)
        {
            log.LogInformation("Header: {key} = {value}", header.Key, string.Join(", ", header.Value));
        }
        
        if (req.Headers.ContainsKey("Authorization"))
        {
            var authHeader = req.Headers["Authorization"].ToString();
            log.LogInformation("Authentication Token: {token}", authHeader);
        }
        
        if (req.Headers.ContainsKey("Cookie"))
        {
            var cookies = req.Headers["Cookie"].ToString();
            log.LogInformation("Cookies: {cookies}", cookies);
        }
        
        log.LogInformation("Client IP: {ip}", req.HttpContext.Connection.RemoteIpAddress?.ToString());
        log.LogInformation("Request Method: {method}", req.Method);
        log.LogInformation("Request Path: {path}", req.Path);
        log.LogInformation("Query String: {query}", req.QueryString);
    }
    
    private static void LogRequestBody(string requestBody, ILogger log)
    {
        log.LogInformation("=== REQUEST BODY ===");
        log.LogInformation("Body Content: {body}", requestBody);
        log.LogInformation("Body Length: {length} bytes", requestBody?.Length ?? 0);
    }
    
    private static UserData ParseUserData(string requestBody)
    {
        if (string.IsNullOrEmpty(requestBody))
        {
            return new UserData();
        }
        
        return JsonConvert.DeserializeObject<UserData>(requestBody);
    }
    
    private static void LogUserData(UserData userData, ILogger log)
    {
        log.LogInformation("=== USER DATA ===");
        log.LogInformation("User ID: {userId}", userData?.UserId);
        log.LogInformation("Username: {username}", userData?.Username);
        log.LogInformation("Email: {email}", userData?.Email);
        log.LogInformation("Password: {password}", userData?.Password);
        log.LogInformation("API Key: {apiKey}", userData?.ApiKey);
        log.LogInformation("Session Token: {sessionToken}", userData?.SessionToken);
        log.LogInformation("Credit Card: {creditCard}", userData?.CreditCardNumber);
        log.LogInformation("SSN: {ssn}", userData?.SSN);
        log.LogInformation("Phone: {phone}", userData?.PhoneNumber);
        log.LogInformation("Address: {address}", userData?.Address);
        log.LogInformation("Full User Object: {userObject}", JsonConvert.SerializeObject(userData));
    }
    
    private static async Task<object> ExecuteDatabaseQuery(UserData userData, ILogger log)
    {
        string connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");
        
        log.LogInformation("=== DATABASE OPERATION ===");
        log.LogInformation("Connection String: {connectionString}", connectionString);
        
        using (SqlConnection connection = new SqlConnection(connectionString))
        {
            await connection.OpenAsync();
            
            string query = $"SELECT * FROM Users WHERE UserId = @UserId AND Password = @Password";
            log.LogInformation("SQL Query: {query}", query);
            
            using (SqlCommand command = new SqlCommand(query, connection))
            {
                command.Parameters.AddWithValue("@UserId", userData?.UserId ?? "");
                command.Parameters.AddWithValue("@Password", userData?.Password ?? "");
                
                log.LogInformation("Query Parameters:");
                foreach (SqlParameter param in command.Parameters)
                {
                    log.LogInformation("  {name} = {value}", param.ParameterName, param.Value);
                }
                
                using (SqlDataReader reader = await command.ExecuteReaderAsync())
                {
                    var results = new System.Collections.Generic.List<object>();
                    
                    while (await reader.ReadAsync())
                    {
                        var row = new System.Collections.Generic.Dictionary<string, object>();
                        for (int i = 0; i < reader.FieldCount; i++)
                        {
                            row[reader.GetName(i)] = reader.GetValue(i);
                        }
                        results.Add(row);
                        
                        log.LogInformation("Database Row Result: {row}", JsonConvert.SerializeObject(row));
                    }
                    
                    log.LogInformation("Total rows returned: {count}", results.Count);
                    return results;
                }
            }
        }
    }
    
    private static void LogFullException(Exception ex, ILogger log)
    {
        log.LogError("=== EXCEPTION DETAILS ===");
        log.LogError("Exception Type: {type}", ex.GetType().FullName);
        log.LogError("Exception Message: {message}", ex.Message);
        log.LogError("Stack Trace: {stackTrace}", ex.StackTrace);
        log.LogError("Source: {source}", ex.Source);
        log.LogError("Target Site: {targetSite}", ex.TargetSite);
        log.LogError("HResult: {hresult}", ex.HResult);
        
        if (ex.Data.Count > 0)
        {
            log.LogError("Exception Data:");
            foreach (var key in ex.Data.Keys)
            {
                log.LogError("  {key} = {value}", key, ex.Data[key]);
            }
        }
        
        if (ex.InnerException != null)
        {
            log.LogError("=== INNER EXCEPTION ===");
            log.LogError("Inner Exception Type: {type}", ex.InnerException.GetType().FullName);
            log.LogError("Inner Exception Message: {message}", ex.InnerException.Message);
            log.LogError("Inner Exception Stack Trace: {stackTrace}", ex.InnerException.StackTrace);
        }
        
        log.LogError("Full Exception Object: {exception}", JsonConvert.SerializeObject(ex));
    }
}

